(function () { 'use strict'; function onReady(fn) { if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', fn); } else { fn(); } } onReady(function () { var menuBtn = document.querySelector('.xt-menu-toggle'); var mobileNav = document.getElementById('xt-mobile-nav'); if (menuBtn && mobileNav) { menuBtn.addEventListener('click', function () { var open = menuBtn.classList.toggle('is-open'); menuBtn.setAttribute('aria-expanded', open ? 'true' : 'false'); if (open) { mobileNav.removeAttribute('hidden'); } else { mobileNav.setAttribute('hidden', ''); } }); } var chatbotFallbackFab = document.getElementById('xt-chatbot-fallback-fab'); if (chatbotFallbackFab) { var chatbotScriptSrc = chatbotFallbackFab.getAttribute('data-chatbot-src') || ''; var openChatbotShell = function () { var realFab = document.querySelector('.xt-chatbot-fab'); if (realFab && !realFab.hidden) { realFab.click(); return true; } return false; }; chatbotFallbackFab.addEventListener('click', function () { if (openChatbotShell()) return; if (chatbotScriptSrc && !document.querySelector('script[src*="assets/js/chatbot.js"]')) { var script = document.createElement('script'); script.src = chatbotScriptSrc; script.defer = true; document.body.appendChild(script); } var attempts = 0; var timer = window.setInterval(function () { attempts += 1; if (openChatbotShell() || attempts > 20) { window.clearInterval(timer); } }, 150); }); } }); })();